94: // CheckTokens checks for leaked tokens.
95: func (s *Service) CheckTokens(ctx context.Context) error {
96: 	// Retrieve all active tokens from the database.
97: 	tokens, err := s.RetrieveActiveTokens(ctx)
98: 	if err != nil {
99: 		return fmt.Errorf("failed to retrieve tokens for checking: %w", err)
100: 	}
101: 
102: 	hashes, hashMap := s.filterCheckableTokens(tokens)
103: 	if len(hashes) == 0 {
104: 		s.logger.Debug("No active tokens to check")
105: 
106: 		return nil
107: 	}
108: 
109: 	// Check if any leaked tokens exist.
110: 	secretscanTokens, err := s.client.CheckTokens(ctx, hashes)
111: 	if err != nil {
112: 		return fmt.Errorf("failed to check tokens: %w", err)
113: 	}
114: 
115: 	// Revoke leaked tokens.
116: 	// Could be done in bulk but we don't expect more than 1 or 2 tokens to be leaked per check.
117: 	for _, secretscanToken := range secretscanTokens {
118: 		secretscanToken := secretscanToken
119: 		leakedToken := hashMap[secretscanToken.Hash]
120: 
121: 		if s.revoke {
122: 			if err := s.store.RevokeServiceAccountToken(
123: 				ctx, leakedToken.OrgID, *leakedToken.ServiceAccountId, leakedToken.ID); err != nil {
124: 				s.logger.Error("Failed to delete leaked token. Revoke manually.",
125: 					"error", err, "url", secretscanToken.URL, "reported_at", secretscanToken.ReportedAt,
126: 					"token_id", leakedToken.ID, "token", leakedToken.Name, "org", leakedToken.OrgID,
127: 					"serviceAccount", *leakedToken.ServiceAccountId)
128: 			}
129: 		}
130: 
131: 		if s.webHookNotify {
132: 			if err := s.webHookClient.Notify(ctx, &secretscanToken, leakedToken.Name, s.revoke); err != nil {
133: 				s.logger.Warn("Failed to call token leak webhook", "error", err)
134: 			}
135: 		}
136: 
137: 		s.logger.Warn("Found leaked token",
138: 			"url", secretscanToken.URL, "reported_at", secretscanToken.ReportedAt,
139: 			"token_id", leakedToken.ID, "token", leakedToken.Name, "org", leakedToken.OrgID,
140: 			"serviceAccount", *leakedToken.ServiceAccountId, "revoked", s.revoke)
141: 	}
142: 
143: 	return nil
144: }
