146: // filterCheckableTokens returns a list of tokens that can be checked and a map of tokens to their hashes.
147: func (*Service) filterCheckableTokens(tokens []apikey.APIKey) ([]string, map[string]apikey.APIKey) {
148: 	hashes := make([]string, 0, len(tokens))
149: 	hashMap := make(map[string]apikey.APIKey)
150: 
151: 	for _, token := range tokens {
152: 		if hasExpired(token.Expires) || (token.IsRevoked != nil && *token.IsRevoked) {
153: 			continue
154: 		}
155: 
156: 		hashes = append(hashes, token.Key)
157: 		hashMap[token.Key] = token
158: 	}
159: 
160: 	return hashes, hashMap
